const body = $json.body ?? {};
const query = String(body.q ?? '').trim();
const limit = Math.min(20, Math.max(1, Number(body.limit ?? 10)));

const mockData = [
  {name: 'Camila Rodriguez', channel: 'Instagram'},
  {name: 'Cami Roldan', channel: 'TikTok'},
  {name: 'Sofia Luna', channel: 'YouTube'},
  {name: 'Mica Torres', channel: 'Instagram'},
  {name: 'Nati Lopez', channel: 'TikTok'},
  {name: 'Agus Costa', channel: 'Instagram'},
  {name: 'Dani Navarro', channel: 'YouTube'},
  {name: 'Vero Diaz', channel: 'Instagram'}
];

const q = query.toLowerCase();
const results = mockData
  .filter(i => i.name.toLowerCase().includes(q))
  .slice(0, limit)
  .map(i => ({name: i.name, channel: i.channel, score: 1}));

return [{json:{ok:true, action:'search', query, total:results.length, items:results}}];
